for (uint256 i = 0; i < targets.length; ++i) {
    (bool controlled, bool withDelay, uint32 nonce) = _getManagerData(plan, i);
    if (controlled) {
        uint32 executedNonce = $._manager.execute{value: values[i]}(targets[i], calldatas[i]);
        if (withDelay && executedNonce != nonce) {
            revert GovernorMismatchedNonce(proposalId, nonce, executedNonce);
        }
    } else {
        (bool success, bytes memory returndata) = targets[i].call{value: values[i]}(calldatas[i]);
        Address.verifyCallResult(success, returndata);
    }
}

for (uint256 i = 0; i < signers.length; i++) {
  if (s_signers[signers[i]].active) revert RepeatedSigner();
  if (signers[i] == ZERO_ADDRESS) revert InvalidSigner();
  s_signers[signers[i]] = Signer({active: true, index: uint8(i)});

  temp = transmitters[i];
  if (temp == ZERO_ADDRESS) revert InvalidTransmitter();
  transmitter = s_transmitters[temp];
  if (transmitter.active) revert RepeatedTransmitter();
  transmitter.active = true;
  transmitter.index = uint8(i);
  // new transmitters start afresh from current totalPremium
  // some spare change of premium from previous pool will be forfeited
  transmitter.lastCollected = totalPremium;
  s_transmitters[temp] = transmitter;
}

if (success) {
    // We'll use DAI's special permit if it's DOMAIN_SEPARATOR matches,
    // otherwise we'll just encode a call to the standard permit function.
    inputData = domainSeparator == DAI_DOMAIN_SEPARATOR
        ? abi.encodeCall(IDAIPermit.permit, (owner, spender, token.nonces(owner), deadline, true, v, r, s))
        : abi.encodeCall(ERC20.permit, (owner, spender, amount, deadline, v, r, s));

    assembly {
        success := call(gas(), token, 0, add(inputData, 32), mload(inputData), 0, 0)
    }
}

PERMIT2.permit(
    owner,
    IAllowanceTransfer.PermitSingle({
        details: IAllowanceTransfer.PermitDetails({
            token: address(token),
            amount: amount.toUint160(),
            // Use an unlimited expiration because it most
            // closely mimics how a standard approval works.
            expiration: type(uint48).max,
            nonce: nonce
        }),
        spender: spender,
        sigDeadline: deadline
    }),
    bytes.concat(r, s, bytes1(v))
);

for(uint256 i = 0; i < withdrawals.length; i++) {
    bytes32 withdrawalRoot = delegationManager.calculateWithdrawalRoot(withdrawals[i]);
