function testLowNonces() public {
    unorderedNonce.spendNonce(address(this), 5);
    unorderedNonce.spendNonce(address(this), 0);
    unorderedNonce.spendNonce(address(this), 1);

    vm.expectRevert(IUnorderedNonce.NonceAlreadyUsed.selector);
    unorderedNonce.spendNonce(address(this), 1);
    vm.expectRevert(IUnorderedNonce.NonceAlreadyUsed.selector);
    unorderedNonce.spendNonce(address(this), 5);
    vm.expectRevert(IUnorderedNonce.NonceAlreadyUsed.selector);
    unorderedNonce.spendNonce(address(this), 0);
    unorderedNonce.spendNonce(address(this), 4);
}

for (uint256 i = 0; i < entries.length; i++) {
    string memory normalizedPath = normalizePath(entries[i].path);
    if (
        normalizedPath.contains(string.concat("/", vm.toString(chainId), "/"))
            && normalizedPath.contains(".json") && !normalizedPath.contains("dry-run")
    ) {
        string memory json = vm.readFile(normalizedPath);
        latestAddress = processRun(json, contractName, latestAddress);
    }
}

assembly {
    // Revert if c == 0 to avoid division by zero
    if iszero(c) {
        revert(0, 0)
    }

    // Overflow check: Ensure a * b does not exceed uint256 max
    if iszero(or(iszero(b), iszero(gt(a, div(not(0), b))))) {
        revert(0, 0)
    }

    let product := mul(a, b)
    d := add(div(product, c), iszero(iszero(mod(product, c))))
}

for (uint256 i = 0; i < calls.length; i++) {
  // Perform low-level call and set return values using result.
  (bool ok, bytes memory returnData) = calls[i].to.call(calls[i].data);
  callResults[i] = CallReturn({ok: ok, returnData: returnData});
  if (!ok) {
    // Exit early - any calls after the first failed call will not execute.
    rollBack = true;
    break;
  }
}

if (deltaBlocks > 0 && supplySpeed > 0) {
    uint supplyTokens = CToken(cToken).totalSupply();
    uint compAccrued = mul_(deltaBlocks, supplySpeed);
    Double memory ratio = supplyTokens > 0 ? fraction(compAccrued, supplyTokens) : Double({mantissa: 0});
    supplyState.index = safe224(
        add_(Double({mantissa: supplyState.index}), ratio).mantissa,
        "new index exceeds 224 bits"
    );
    supplyState.block = blockNumber;
} else if (deltaBlocks > 0) {
    supplyState.block = blockNumber;
}

try vulcan.hevm.tryFfi(inputs) returns (VmSafe.FfiResult memory ffiResult) {
    CommandOutput memory output;

    output.exitCode = ffiResult.exitCode;
    output.stdout = ffiResult.stdout;
    output.stderr = ffiResult.stderr;
    output.command = Command(inputs);

    return Ok(output);
} catch Error(string memory message) {
    return CommandError.NotExecuted(message).toCommandResult();
} catch (bytes memory data) {
    string memory message = abi.decode(removeSelector(data), (string));
    return CommandError.NotExecuted(message).toCommandResult();
}

for (uint256 i = 0; i < newSignersLength; i++) {
    (uint256 deadline, bytes memory signer, bytes memory signature) = abi.decode(
        newSigners[i],
        (uint256, bytes, bytes)
    );
    require(deadline > block.timestamp, ERC7579MultisigExpiredConfirmation(deadline));
    require(
        SignatureChecker.isValidSignatureNow(signer, _signableConfirmationHash(account, deadline), signature),
        ERC7579MultisigInvalidConfirmationSignature(signer)
    );
    newSigners[i] = signer; // Replace the ABI-encoded value with the signer
}

if (newMember) {
    since = Time.timestamp() + grantDelay;
    _roles[roleId].members[account] = Access({since: since, delay: executionDelay.toDelay()});
} else {
    // No setback here. Value can be reset by doing revoke + grant, effectively allowing the admin to perform
    // any change to the execution delay within the duration of the role admin delay.
    (_roles[roleId].members[account].delay, since) = _roles[roleId].members[account].delay.withUpdate(
        executionDelay,
        0
    );
}

if (signature.length >= 20) {
    (address module, bytes calldata innerSignature) = _extractSignatureValidator(signature);
    // if module is not installed, skip
    if (isModuleInstalled(MODULE_TYPE_VALIDATOR, module, Calldata.emptyBytes())) {
        // try validation, skip any revert
        try IERC7579Validator(module).isValidSignatureWithSender(msg.sender, hash, innerSignature) returns (
            bytes4 magic
        ) {
            return magic;
        } catch {}
    }
}

for (uint256 i = 0; i < values.length; i++) {
  Report memory report = _getReport(values[i]);
  string memory feedId = _bytes32ToHexString(abi.encodePacked(report.feedId));
  Feed memory feed = s_feedMapping[feedId];
  if (
    (report.observationsTimestamp - feed.observationsTimestamp > feed.stalenessSeconds) ||
    deviationExceedsThreshold(feed.price, report.price, feed.deviationPercentagePPM)
  ) {
    filteredValues[count] = values[i];
    count++;
  }
}

